const b = $input.first().json.body || {};
const complaintId     = parseInt(b.complaintId);
const uid             = parseInt(b.uid || 1);
const remarks         = b.remarks || '';
const txnId           = b.txnId || '';
const mobileCalled    = b.mobileCalled || '';
const escalationLevel = parseInt(b.escalationLevel || 1);
const delayMain       = b.delayMain || '';
const delaySub        = b.delaySub  || '';

if (!complaintId) return [{ json: { success: false, error: 'complaintId required' } }];

// Use EDC from frontend if provided; fall back to today + 3 days
let newClosureDate = (b.newClosureDate || '').trim();
if (!newClosureDate) {
  const edc = new Date(); edc.setDate(edc.getDate() + 3);
  newClosureDate = edc.toISOString().split('T')[0];
}

const sqlCountNc = `SELECT COUNT(*) AS nc_count FROM vmm_complaintlogs WHERE complaintid = ${complaintId} AND status = 'Not Connected'`;

return [{ json: { sqlCountNc, complaintId, uid, remarks, txnId, mobileCalled, newClosureDate, escalationLevel, delayMain, delaySub } }];

const prev    = $('Prepare').first().json;
const ncRow   = $input.first().json;
const ncCount = parseInt(ncRow.nc_count ?? ncRow[0]?.nc_count ?? 0);
const rLevel  = ncCount + 1;
const rLabel  = rLevel === 1 ? 'R1 - First Attempt' : rLevel === 2 ? 'R2 - Second Attempt' : 'R3+ - Escalation Required';

const esc = v => (v || '').toString().replace(/'/g, "''");

const parts = ['Called - Not Connected | ' + rLabel];
if (prev.txnId) parts.push('TXN: ' + prev.txnId);
if (prev.mobileCalled) parts.push('Mobile: ' + prev.mobileCalled);
if (prev.remarks) parts.push(prev.remarks);
parts.push('Source: Call');
if (prev.delayMain) {
  const delayStr = prev.delaySub ? prev.delayMain + ' > ' + prev.delaySub : prev.delayMain;
  parts.push('Delay: ' + delayStr);
}

const fullRemarks = esc(parts.filter(Boolean).join(' | '));

const insertLog = `INSERT INTO vmm_complaintlogs (complaintid, remarks, status, uid, created, is_deleted) VALUES (${prev.complaintId}, '${fullRemarks}', 'Not Connected', ${prev.uid}, NOW(), 'No')`;

const insertEsc = `INSERT INTO vmm_vendorescalations (complaintid, escalationlevel, ticketno, closuredate, uid, created, is_deleted) VALUES (${prev.complaintId}, ${prev.escalationLevel}, '', '${prev.newClosureDate}', ${prev.uid}, NOW(), 'No')`;

return [{ json: { insertLog, insertEsc, complaintId: prev.complaintId, rLevel, uid: prev.uid, newClosureDate: prev.newClosureDate } }];

const d   = $('Build Log').first().json;
const row = $input.first().json;

const bufStr = v => {
  if (v == null) return '';
  if (typeof v === 'object' && v.type === 'Buffer' && Array.isArray(v.data)) {
    try { return new TextDecoder().decode(new Uint8Array(v.data)); } catch { return ''; }
  }
  return String(v);
};

const TEST_MODE   = true;
const TEST_TO     = 'inder@openmind.in';
const ALWAYS_CC   = 'VMM Team <54933595.openmindservices.onmicrosoft.com@in.teams.ms>';

const complaintno      = bufStr(row.complaintno);
const productName      = bufStr(row.productname) || 'the product';
const storeName        = bufStr(row.storename)   || 'Store';
const storeCode        = bufStr(row.storecode);
const storeEmail       = bufStr(row.storeemail)  || 'vmm@openmindserviceslimited.in';
const fmEmail          = bufStr(row.fmemail);
const escalationMsgId  = bufStr(row.escalation_messageid);

const toEmail = TEST_MODE ? TEST_TO : storeEmail;

const ccParts = [];
if (!TEST_MODE && fmEmail) ccParts.push(fmEmail);
if (ALWAYS_CC) ALWAYS_CC.split(',').map(e => e.trim()).filter(Boolean).forEach(e => { if (!ccParts.includes(e)) ccParts.push(e); });
const ccEmails = ccParts.join(';');

return [{ json: {
  escalationMsgId,
  rLevel:      d.rLevel,
  complaintno,
  storeName,
  storeCode,
  productName,
  newEdc:      d.newClosureDate,
  toEmail,
  ccEmails,
  complaintId: d.complaintId,
  newClosureDate: d.newClosureDate,
} }];

const d = $('Build NC Payload').first().json;
const reminderRes = $input.first().json || {};
return [{ json: {
  success: true,
  complaintId:    d.complaintId,
  rLevel:         d.rLevel,
  newEdc:         d.newClosureDate,
  reminderSent:   reminderRes.success === true && !reminderRes.skipped,
  message: 'Not Connected R' + d.rLevel + ' logged. EDC set to ' + d.newClosureDate + (reminderRes.success && !reminderRes.skipped ? '. Reminder reply sent on escalation thread.' : '. No escalation email on file — reminder skipped.')
} }];
